/**
 * Kitchen Display Module Types
 *
 * Type definitions for future kitchen display system (KDS) implementation.
 * This file defines interfaces for order queue management, station displays,
 * and kitchen operations.
 *
 * @module modules/_stubs/kitchen-display/types
 *
 * @example
 * ```typescript
 * import type {
 *   IKitchenDisplayService,
 *   KitchenOrder,
 *   KitchenStation,
 * } from '@/modules/_stubs/kitchen-display';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * Kitchen order status
 */
export enum KitchenOrderStatus {
  /** Order received, waiting */
  PENDING = 'PENDING',
  /** Order being prepared */
  IN_PROGRESS = 'IN_PROGRESS',
  /** Order ready for pickup */
  READY = 'READY',
  /** Order picked up/served */
  SERVED = 'SERVED',
  /** Order recalled for modifications */
  RECALLED = 'RECALLED',
  /** Order cancelled */
  CANCELLED = 'CANCELLED',
}

/**
 * Kitchen item status
 */
export enum KitchenItemStatus {
  /** Waiting to be prepared */
  WAITING = 'WAITING',
  /** Being prepared */
  PREPARING = 'PREPARING',
  /** Ready */
  READY = 'READY',
  /** Delayed */
  DELAYED = 'DELAYED',
  /** Cancelled */
  CANCELLED = 'CANCELLED',
}

/**
 * Station type
 */
export enum StationType {
  /** Main kitchen */
  MAIN_KITCHEN = 'MAIN_KITCHEN',
  /** Grill station */
  GRILL = 'GRILL',
  /** Cold station (salads, desserts) */
  COLD = 'COLD',
  /** Drinks/beverage station */
  BEVERAGE = 'BEVERAGE',
  /** Fryer station */
  FRYER = 'FRYER',
  /** Pastry station */
  PASTRY = 'PASTRY',
  /** Expo/expeditor */
  EXPO = 'EXPO',
  /** Custom station */
  CUSTOM = 'CUSTOM',
}

/**
 * Priority level
 */
export enum PriorityLevel {
  /** Normal priority */
  NORMAL = 'NORMAL',
  /** Rush order */
  RUSH = 'RUSH',
  /** VIP order */
  VIP = 'VIP',
  /** Fire (immediate) */
  FIRE = 'FIRE',
}

/**
 * Alert type
 */
export enum KitchenAlertType {
  /** Order delayed */
  ORDER_DELAYED = 'ORDER_DELAYED',
  /** Item delayed */
  ITEM_DELAYED = 'ITEM_DELAYED',
  /** All day count reached */
  ALL_DAY_ALERT = 'ALL_DAY_ALERT',
  /** Station backup */
  STATION_BACKUP = 'STATION_BACKUP',
  /** Rush hour alert */
  RUSH_HOUR = 'RUSH_HOUR',
  /** Item 86d (out of stock) */
  ITEM_86 = 'ITEM_86',
}

// -----------------------------------------------------------------------------
// Entity Types
// -----------------------------------------------------------------------------

/**
 * Kitchen order (view for KDS)
 */
export interface KitchenOrder {
  /** Order ID */
  id: string;
  /** Original order ID */
  orderId: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Order number */
  orderNumber: string;
  /** Table number */
  tableNumber: string | null;
  /** Status */
  status: KitchenOrderStatus;
  /** Priority */
  priority: PriorityLevel;
  /** Items */
  items: KitchenOrderItem[];
  /** Customer name */
  customerName: string | null;
  /** Special instructions */
  instructions: string | null;
  /** Order type (dine-in, takeout, etc.) */
  orderType: string;
  /** Time received */
  receivedAt: Date;
  /** Time started */
  startedAt: Date | null;
  /** Time ready */
  readyAt: Date | null;
  /** Time served */
  servedAt: Date | null;
  /** Target time (when should be ready) */
  targetTime: Date | null;
  /** Is delayed */
  isDelayed: boolean;
  /** Wait time (seconds) */
  waitTimeSeconds: number;
}

/**
 * Kitchen order item
 */
export interface KitchenOrderItem {
  /** Item ID */
  id: string;
  /** Menu item ID */
  menuItemId: string;
  /** Item name */
  name: string;
  /** Quantity */
  quantity: number;
  /** Status */
  status: KitchenItemStatus;
  /** Station ID */
  stationId: string | null;
  /** Modifiers */
  modifiers: string[];
  /** Special notes */
  notes: string | null;
  /** Preparation time (minutes) */
  prepTimeMinutes: number;
  /** Started at */
  startedAt: Date | null;
  /** Ready at */
  readyAt: Date | null;
}

/**
 * Kitchen station
 */
export interface KitchenStation {
  /** Station ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Station name */
  name: string;
  /** Station type */
  type: StationType;
  /** Display order */
  displayOrder: number;
  /** Is active */
  isActive: boolean;
  /** Assigned menu items (IDs) */
  assignedItems: string[];
  /** Color for display */
  color: string;
  /** Current queue count */
  queueCount: number;
  /** Average prep time (minutes) */
  avgPrepTimeMinutes: number;
}

/**
 * Kitchen alert
 */
export interface KitchenAlert {
  /** Alert ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Alert type */
  type: KitchenAlertType;
  /** Related order ID */
  orderId: string | null;
  /** Related item ID */
  itemId: string | null;
  /** Related station ID */
  stationId: string | null;
  /** Message */
  message: string;
  /** Is acknowledged */
  isAcknowledged: boolean;
  /** Acknowledged by */
  acknowledgedBy: string | null;
  /** Created at */
  createdAt: Date;
  /** Acknowledged at */
  acknowledgedAt: Date | null;
}

/**
 * Kitchen display settings
 */
export interface KitchenDisplaySettings {
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Order alert threshold (seconds) */
  orderAlertThresholdSeconds: number;
  /** Item alert threshold (seconds) */
  itemAlertThresholdSeconds: number;
  /** Auto-complete orders */
  autoCompleteOrders: boolean;
  /** Show customer names */
  showCustomerNames: boolean;
  /** Show order totals */
  showOrderTotals: boolean;
  /** Enable audio alerts */
  audioAlertsEnabled: boolean;
  /** Display columns */
  displayColumns: number;
  /** Group by station */
  groupByStation: boolean;
  /** Sort order */
  sortOrder: 'oldest_first' | 'priority' | 'station';
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create station request
 */
export interface CreateStationRequest {
  /** Branch ID */
  branchId: string;
  /** Station name */
  name: string;
  /** Station type */
  type: StationType;
  /** Color */
  color?: string;
  /** Assigned menu item IDs */
  assignedItems?: string[];
}

/**
 * Update station request
 */
export interface UpdateStationRequest {
  /** Station name */
  name?: string;
  /** Station type */
  type?: StationType;
  /** Display order */
  displayOrder?: number;
  /** Is active */
  isActive?: boolean;
  /** Color */
  color?: string;
  /** Assigned menu item IDs */
  assignedItems?: string[];
}

/**
 * Update item status request
 */
export interface UpdateItemStatusRequest {
  /** Item ID */
  itemId: string;
  /** New status */
  status: KitchenItemStatus;
}

/**
 * Bump order request
 */
export interface BumpOrderRequest {
  /** Order ID */
  orderId: string;
  /** Bump to status */
  status: KitchenOrderStatus;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Kitchen queue
 */
export interface KitchenQueue {
  /** Station ID (null for all stations) */
  stationId: string | null;
  /** Orders in queue */
  orders: KitchenOrder[];
  /** Total count */
  totalCount: number;
  /** Oldest order wait time (seconds) */
  oldestWaitTimeSeconds: number;
  /** Average wait time (seconds) */
  avgWaitTimeSeconds: number;
}

/**
 * Kitchen performance
 */
export interface KitchenPerformance {
  /** Period start */
  periodStart: Date;
  /** Period end */
  periodEnd: Date;
  /** Total orders */
  totalOrders: number;
  /** Completed orders */
  completedOrders: number;
  /** Average prep time (minutes) */
  avgPrepTimeMinutes: number;
  /** Orders on time percentage */
  onTimePercentage: number;
  /** Delayed orders */
  delayedOrders: number;
  /** Station breakdown */
  stationPerformance: Array<{
    stationId: string;
    stationName: string;
    itemsCompleted: number;
    avgPrepTimeMinutes: number;
  }>;
}

/**
 * All-day count (running totals)
 */
export interface AllDayCount {
  /** Item ID */
  itemId: string;
  /** Item name */
  itemName: string;
  /** Ordered count */
  ordered: number;
  /** Completed count */
  completed: number;
  /** In progress count */
  inProgress: number;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * Kitchen display service interface
 */
export interface IKitchenDisplayService {
  /**
   * Get kitchen queue
   */
  getQueue(
    organizationId: string,
    branchId: string,
    stationId?: string
  ): Promise<KitchenQueue>;

  /**
   * Get order details
   */
  getOrder(
    organizationId: string,
    orderId: string
  ): Promise<KitchenOrder>;

  /**
   * Update order status
   */
  updateOrderStatus(
    organizationId: string,
    orderId: string,
    status: KitchenOrderStatus
  ): Promise<KitchenOrder>;

  /**
   * Update item status
   */
  updateItemStatus(
    organizationId: string,
    request: UpdateItemStatusRequest
  ): Promise<KitchenOrderItem>;

  /**
   * Bump order (mark as ready/served)
   */
  bumpOrder(
    organizationId: string,
    request: BumpOrderRequest
  ): Promise<KitchenOrder>;

  /**
   * Recall order
   */
  recallOrder(
    organizationId: string,
    orderId: string
  ): Promise<KitchenOrder>;

  /**
   * Set order priority
   */
  setOrderPriority(
    organizationId: string,
    orderId: string,
    priority: PriorityLevel
  ): Promise<KitchenOrder>;

  /**
   * Get active alerts
   */
  getAlerts(
    organizationId: string,
    branchId: string
  ): Promise<KitchenAlert[]>;

  /**
   * Acknowledge alert
   */
  acknowledgeAlert(
    organizationId: string,
    alertId: string
  ): Promise<KitchenAlert>;

  /**
   * Get all-day counts
   */
  getAllDayCounts(
    organizationId: string,
    branchId: string
  ): Promise<AllDayCount[]>;

  /**
   * Get kitchen performance
   */
  getPerformance(
    organizationId: string,
    branchId: string,
    startDate: string,
    endDate: string
  ): Promise<KitchenPerformance>;
}

/**
 * Order queue service interface
 */
export interface IOrderQueueService {
  /**
   * Add order to queue
   */
  addToQueue(
    organizationId: string,
    orderId: string
  ): Promise<KitchenOrder>;

  /**
   * Remove order from queue
   */
  removeFromQueue(
    organizationId: string,
    orderId: string
  ): Promise<void>;

  /**
   * Reorder queue
   */
  reorderQueue(
    organizationId: string,
    branchId: string,
    orderIds: string[]
  ): Promise<void>;

  /**
   * Get queue stats
   */
  getQueueStats(
    organizationId: string,
    branchId: string
  ): Promise<{
    totalOrders: number;
    pendingOrders: number;
    inProgressOrders: number;
    readyOrders: number;
    avgWaitTimeMinutes: number;
  }>;
}

/**
 * Station service interface
 */
export interface IStationService {
  /**
   * Create station
   */
  createStation(
    organizationId: string,
    request: CreateStationRequest
  ): Promise<KitchenStation>;

  /**
   * Get station by ID
   */
  getStation(
    organizationId: string,
    stationId: string
  ): Promise<KitchenStation>;

  /**
   * List stations
   */
  listStations(
    organizationId: string,
    branchId: string
  ): Promise<KitchenStation[]>;

  /**
   * Update station
   */
  updateStation(
    organizationId: string,
    stationId: string,
    request: UpdateStationRequest
  ): Promise<KitchenStation>;

  /**
   * Delete station
   */
  deleteStation(
    organizationId: string,
    stationId: string
  ): Promise<void>;

  /**
   * Assign items to station
   */
  assignItems(
    organizationId: string,
    stationId: string,
    itemIds: string[]
  ): Promise<KitchenStation>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Order received event payload
 */
export interface KdsOrderReceivedEventPayload {
  organizationId: string;
  branchId: string;
  orderId: string;
  orderNumber: string;
  itemCount: number;
  priority: PriorityLevel;
  timestamp: string;
}

/**
 * Order ready event payload
 */
export interface KdsOrderReadyEventPayload {
  organizationId: string;
  orderId: string;
  orderNumber: string;
  prepTimeMinutes: number;
  timestamp: string;
}

/**
 * Order delayed event payload
 */
export interface KdsOrderDelayedEventPayload {
  organizationId: string;
  orderId: string;
  orderNumber: string;
  delayedByMinutes: number;
  timestamp: string;
}

/**
 * Station alert event payload
 */
export interface KdsStationAlertEventPayload {
  organizationId: string;
  branchId: string;
  stationId: string;
  alertType: KitchenAlertType;
  message: string;
  queueCount: number;
  timestamp: string;
}
